class PIISanitizer:
    """Sanitizes PII data for logging purposes."""
    
    @staticmethod
    def mask_email(email: str) -> str:
        if not email or '@' not in email:
            return '***'
        local, domain = email.rsplit('@', 1)
        masked_local = local[0] + '***' if len(local) > 0 else '***'
        return f"{masked_local}@{domain}"
    
    @staticmethod
    def mask_phone(phone: str) -> str:
        if not phone or len(phone) < 4:
            return '***'
        return '***' + phone[-4:]
    
    @staticmethod
    def mask_address(address: str) -> str:
        if not address:
            return '***'
        return '***REDACTED***'
    
    @staticmethod
    def sanitize_user_data(user_data: dict) -> dict:
        """Return a sanitized copy of user data safe for logging."""
        sanitized = {}
        for key, value in user_data.items():
            if key in ('email',):
                sanitized[key] = PIISanitizer.mask_email(value)
            elif key in ('phone', 'phone_number'):
                sanitized[key] = PIISanitizer.mask_phone(value)
            elif key in ('address', 'street_address', 'mailing_address'):
                sanitized[key] = PIISanitizer.mask_address(value)
            elif key in ('ssn', 'social_security_number', 'credit_card', 'password'):
                sanitized[key] = '***REDACTED***'
            else:
                sanitized[key] = value
        return sanitized


class InputValidator:
    """Validates user data before publishing."""
    
    MAX_MESSAGE_SIZE = 256 * 1024  # 256 KB SQS limit
    ALLOWED_FIELDS = {
        'user_id', 'email', 'phone', 'phone_number', 'first_name',
        'last_name', 'address', 'street_address', 'mailing_address',
        'city', 'state', 'zip_code', 'country'
    }
    
    @staticmethod
    def validate_email(email: str) -> bool:
        if not isinstance(email, str):
            return False
        if len(email) > 254:
            return False
        if '@' not in email:
            return False
        local, domain = email.rsplit('@', 1)
        if not local or not domain or '.' not in domain:
            return False
        return True
    
    @staticmethod
    def validate_phone(phone: str) -> bool:
        if not isinstance(phone, str):
            return False
        cleaned = phone.replace('-', '').replace(' ', '').replace('(', '').replace(')', '').replace('+', '')
        if not cleaned.isdigit():
            return False
        if len(cleaned) < 7 or len(cleaned) > 15:
            return False
        return True
    
    @staticmethod
    def validate_string_field(value: str, max_length: int = 500) -> bool:
        if not isinstance(value, str):
            return False
        if len(value) > max_length:
            return False
        return True
    
    @classmethod
    def validate_user_data(cls, user_data: dict) -> tuple:
        """Validate user data. Returns (is_valid, error_message)."""
        if not isinstance(user_data, dict):
            return False, "User data must be a dictionary"
        
        if not user_data:
            return False, "User data cannot be empty"
        
        # Check for unexpected fields
        unexpected_fields = set(user_data.keys()) - cls.ALLOWED_FIELDS
        if unexpected_fields:
            return False, f"Unexpected fields: {unexpected_fields}"
        
        # Validate required field
        if 'user_id' not in user_data:
            return False, "user_id is required"
        
        if not cls.validate_string_field(str(user_data['user_id']), max_length=128):
            return False, "Invalid user_id"
        
        # Validate email if present
        if 'email' in user_data and not cls.validate_email(user_data['email']):
            return False, "Invalid email format"
        
        # Validate phone if present
        for phone_field in ('phone', 'phone_number'):
            if phone_field in user_data and not cls.validate_phone(user_data[phone_field]):
                return False, f"Invalid {phone_field} format"
        
        # Validate string fields
        for key, value in user_data.items():
            if key == 'user_id':
                continue
            if isinstance(value, str) and not cls.validate_string_field(value):
                return False, f"Field {key} exceeds maximum length"
        
        # Check serialized size
        serialized = json.dumps(user_data)
        if len(serialized.encode('utf-8')) > cls.MAX_MESSAGE_SIZE:
            return False, "Message exceeds maximum size"
        
        return True, None


class SQSUserDataPublisher:
    """
    Publishes user data messages to an SQS queue.
    
    Expects the SQS queue to have:
    - Server-side encryption (SSE) enabled with KMS
    - Appropriate IAM policies restricting access
    - A dead-letter queue configured for failed messages
    
    The publisher uses HTTPS (default boto3 behavior) for data in transit.
    """
    
    def __init__(self, queue_url: str, region_name: str = 'us-east-1',
                 kms_key_id: str = None):
        """
        Initialize the SQS publisher.
        
        Args:
            queue_url: The URL of the SQS queue (must be HTTPS).
            region_name: AWS region.
            kms_key_id: Optional KMS key ID for per-message encryption.
        """
        if not queue_url or not queue_url.startswith('https://'):
            raise ValueError("Queue URL must use HTTPS")
        
        self._queue_url = queue_url
        self._kms_key_id = kms_key_id
        self._sanitizer = PIISanitizer()
        self._validator = InputValidator()
        
        # boto3 uses HTTPS by default for SQS endpoints
        self._sqs_client = boto3.client(
            'sqs',
            region_name=region_name,
            config=boto3.session.Config(
                retries={'max_attempts': 3, 'mode': 'adaptive'},
                connect_timeout=5,
                read_timeout=10
            )
        )
    
    def _build_message_body(self, user_data: dict, event_type: str) -> str:
        """Build the message body with metadata."""
        message = {
            'message_id': str(uuid.uuid4()),
            'event_type': event_type,
            'timestamp': datetime.utcnow().isoformat() + 'Z',
            'data_classification': 'PII',
            'user_data': user_data
        }
        return json.dumps(message, default=str)
    
    def _build_message_attributes(self, event_type: str) -> dict:
        """Build SQS message attributes."""
        attributes = {
            'EventType': {
                'DataType': 'String',
                'StringValue': event_type
            },
            'DataClassification': {
                'DataType': 'String',
                'StringValue': 'PII'
            },
            'Timestamp': {
                'DataType': 'String',
                'StringValue': datetime.utcnow().isoformat() + 'Z'
            }
        }
        return attributes
    
    def publish_user_data(self, user_data: dict, event_type: str = 'user_data_update',
                          deduplication_id: str = None, message_group_id: str = None) -> dict:
        """
        Publish user data message to SQS.
        
        Args:
            user_data: Dictionary containing user data (may include PII).
            event_type: Type of event being published.
            deduplication_id: Optional deduplication ID for FIFO queues.
            message_group_id: Optional message group ID for FIFO queues.
        
        Returns:
            dict with message_id and status.
        
        Raises:
            ValueError: If user data is invalid.
            ClientError: If SQS publish fails after retries.
        """
        # Validate input
        is_valid, error_message = self._validator.validate_user_data(user_data)
        if not is_valid:
            logger.error("Validation failed: %s", error_message)
            raise ValueError(f"Invalid user data: {error_message}")
        
        if not isinstance(event_type, str) or len(event_type) > 256:
            raise ValueError("Invalid event_type")
        
        # Build message
        message_body = self._build_message_body(user_data, event_type)
        message_attributes = self._build_message_attributes(event_type)
        
        send_kwargs = {
            'QueueUrl': self._queue_url,
            'MessageBody': message_body,
            'MessageAttributes': message_attributes
        }
        
        # FIFO queue support
        if self._queue_url.endswith('.fifo'):
            send_kwargs['MessageDeduplicationId'] = deduplication_id or str(uuid.uuid4())
            send_kwargs['MessageGroupId'] = message_group_id or user_data.get('user_id', 'default')
        
        # Log sanitized data only - never log raw PII
        sanitized = self._sanitizer.sanitize_user_data(user_data)
        logger.info(
            "Publishing user data message: event_type=%s, user_id=%s, sanitized_data=%s",
            event_type,
            user_data.get('user_id', 'unknown'),
            json.dumps(sanitized)
        )
        
        try:
            response = self._sqs_client.send_message(**send_kwargs)
            
            sqs_message_id = response.get('MessageId', 'unknown')
            logger.info(
                "Successfully published message: sqs_message_id=%s, user_id=%s, event_type=%s",
                sqs_message_id,
                user_data.get('user_id', 'unknown'),
                event_type
            )
            
            return {
                'status': 'success',
                'sqs_message_id': sqs_message_id,
                'md5_of_body': response.get('MD5OfMessageBody'),
            }
        
        except ClientError as e:
            error_code = e.response['Error']['Code']
            # Log error without PII
            logger.error(
                "Failed to publish message: error_code=%s, user_id=%s, event_type=%s",
                error_code,
                user_data.get('user_id', 'unknown'),
                event_type
            )
            raise
    
    def publish_batch(self, user_data_list: list, event_type: str = 'user_data_update') -> dict:
        """
        Publish a batch of user data messages (up to 10).
        
        Args:
            user_data_list: List of user data dictionaries.
            event_type: Type of event.
        
        Returns:
            dict with successful and failed message counts.
        """
        if not isinstance(user_data_list, list):
            raise ValueError("user_data_list must be a list")
        
        if len(user_data_list) > 10:
            raise ValueError("SQS batch limit is 10 messages")
        
        if len(user_data_list) == 0:
            return {'successful': 0, 'failed': 0, 'results': []}
        
        entries = []
        for idx, user_data in enumerate(user_data_list):
            is_valid, error_message = self._validator.validate_user_data(user_data)
            if not is_valid:
                logger.error("Validation failed for batch item %d: %s", idx, error_message)
                raise ValueError(f"Invalid user data at index {idx}: {error_message}")
            
            entry_id = str(uuid.uuid4())
            message_body = self._build_message_body(user_data, event_type)
            message_attributes = self._build_message_attributes(event_type)
            
            entry = {
                'Id': entry_id,
                'MessageBody': message_body,
                'MessageAttributes': message_attributes
            }
            
            if self._queue_url.endswith('.fifo'):
                entry['MessageDeduplicationId'] = str(uuid.uuid4())
                entry['MessageGroupId'] = user_data.get('user_id', 'default')
            
            entries.append(entry)
        
        # Log sanitized batch info
        logger.info(
            "Publishing batch of %d user data messages, event_type=%s",
            len(entries),
            event_type
        )
        
        try:
            response = self._sqs_client.send_message_batch(
                QueueUrl=self._queue_url,
                Entries=entries
            )
            
            successful = response.get('Successful', [])
            failed = response.get('Failed', [])
            
            if failed:
                logger.error(
                    "Batch publish had %d failures out of %d messages",
                    len(failed),
                    len(entries)
                )
                for failure in failed:
                    logger.error(
                        "Batch failure: id=%s, code=%s, sender_fault=%s",
                        failure.get('Id'),
                        failure.get('Code'),
                        failure.get('SenderFault')
                    )
            
            logger.info(
                "Batch publish complete: successful=%d, failed=%d",
                len(successful),
                len(failed)
            )
            
            return {
                'successful': len(successful),
                'failed': len(failed),
                'successful_ids': [s['MessageId'] for s in successful],
                'failed_entries': [{'id': f['Id'], 'code': f['Code']} for f in failed]
            }
        
        except ClientError as e:
            logger.error("Batch publish failed: %s", e.response['Error']['Code'])
            raise


